function solve(s: string): number {
    const n = s.length;

    // We only need to check indices i such that i <= n - i - 1, 
    // because if a match occurs at i' > (n-1)/2, the corresponding 
    // index j' = n - i' - 1 would be smaller than i', and we would have found 
    // the match at j' first, provided j' is also within the iteration range 
    // (which it is, since j' >= 0).
    // The upper bound for i is floor((n - 1) / 2).
    const limit = Math.floor((n - 1) / 2);

    for (let i = 0; i <= limit; i++) {
        // Check if the character at index i matches the character at the symmetric position
        if (s[i] === s[n - i - 1]) {
            // Since we iterate from i=0 upwards, this is the smallest such index.
            return i;
        }
    }

    // If no such index is found
    return -1;
}
